using UnityEngine;
using UnityEngine.AI;

public class EnemyAI : MonoBehaviour
{
    public enum EnemyState
    {
        Idle,
        Patrol,
        Chase,
        Attack,
        Dead
    }

    [Header("References")]
    public Transform player;
    public NavMeshAgent agent;
    public Animator animator;
    public HealthComponent health;

    [Header("States")]
    public EnemyState currentState = EnemyState.Patrol;
    public float detectionRange = 10f;
    public float attackRange = 2f;
    public float patrolRange = 5f;
    public float chaseSpeed = 5f;
    public float patrolSpeed = 2f;

    [Header("Attack")]
    public int attackDamage = 10;
    public float attackCooldown = 1f;
    private float lastAttackTime;

    private Vector3 patrolTarget;
    private bool hasPatrolTarget;

    void Start()
    {
        if (agent == null)
            agent = GetComponent<NavMeshAgent>();
        if (animator == null)
            animator = GetComponent<Animator>();
        if (health == null)
            health = GetComponent<HealthComponent>();

        if (player == null)
        {
            GameObject playerObj = GameObject.FindGameObjectWithTag("Player");
            if (playerObj != null)
                player = playerObj.transform;
        }

        // Set initial state
        SetState(EnemyState.Patrol);
    }

    void Update()
    {
        if (currentState == EnemyState.Dead) return;
        if (player == null) return;

        // Check state transitions
        float distanceToPlayer = Vector3.Distance(transform.position, player.position);

        if (distanceToPlayer <= detectionRange && currentState != EnemyState.Dead)
        {
            SetState(EnemyState.Chase);
        }
        else if (distanceToPlayer > detectionRange && currentState == EnemyState.Chase)
        {
            SetState(EnemyState.Patrol);
        }

        // Handle current state
        switch (currentState)
        {
            case EnemyState.Idle:
                UpdateIdle();
                break;
            case EnemyState.Patrol:
                UpdatePatrol();
                break;
            case EnemyState.Chase:
                UpdateChase();
                break;
            case EnemyState.Attack:
                UpdateAttack();
                break;
        }

        // Animation
        float speed = agent.velocity.magnitude;
        animator.SetFloat("Speed", speed);
        animator.SetBool("IsChasing", currentState == EnemyState.Chase);
        animator.SetBool("IsAttacking", currentState == EnemyState.Attack);
    }

    void UpdateIdle()
    {
        // Wait for something to happen
        // Could add a timer to transition to patrol
    }

    void UpdatePatrol()
    {
        agent.speed = patrolSpeed;

        if (!hasPatrolTarget || agent.remainingDistance < 0.5f)
        {
            SetNewPatrolTarget();
        }

        animator.SetBool("IsMoving", agent.remainingDistance > 0.5f);
    }

    void UpdateChase()
    {
        agent.speed = chaseSpeed;
        agent.SetDestination(player.position);
        animator.SetBool("IsMoving", true);

        if (Vector3.Distance(transform.position, player.position) <= attackRange)
        {
            SetState(EnemyState.Attack);
        }
    }

    void UpdateAttack()
    {
        agent.velocity = Vector3.zero;

        if (Time.time > lastAttackTime + attackCooldown)
        {
            lastAttackTime = Time.time;

            // Attack animation
            animator.SetTrigger("Attack");

            // Deal damage
            HealthComponent playerHealth = player.GetComponent<HealthComponent>();
            if (playerHealth != null)
            {
                playerHealth.TakeDamage(attackDamage);
                Debug.Log("Enemy attacked for " + attackDamage + " damage!");
            }
        }

        // Check if player moved away
        if (Vector3.Distance(transform.position, player.position) > attackRange)
        {
            SetState(EnemyState.Chase);
        }
    }

    void SetState(EnemyState newState)
    {
        currentState = newState;

        switch (newState)
        {
            case EnemyState.Patrol:
                hasPatrolTarget = false;
                break;
            case EnemyState.Chase:
                break;
            case EnemyState.Attack:
                agent.velocity = Vector3.zero;
                break;
        }
    }

    void SetNewPatrolTarget()
    {
        Vector3 randomDirection = Random.insideUnitSphere * patrolRange;
        randomDirection += transform.position;

        NavMeshHit hit;
        if (NavMesh.SamplePosition(randomDirection, out hit, patrolRange, NavMesh.AllAreas))
        {
            patrolTarget = hit.position;
            agent.SetDestination(patrolTarget);
            hasPatrolTarget = true;
        }
    }

    public void Die()
    {
        SetState(EnemyState.Dead);
        agent.enabled = false;
        animator.SetTrigger("Death");

        Debug.Log("Enemy defeated!");
    }
}

